use std::env;

#[derive(Debug)]
pub struct GameState { 
    board_data: Vec<u8>,
}

impl GameState {
    pub fn new() -> Self {
        GameState { board_data: vec![0; 64] }
    }

    pub fn process_move(&self, piece_type: &str) -> bool {
        if piece_type.contains('K') || piece_type.contains('Q') {
            println!("Successfully processed move for type: {}", piece_type);
            return true;
        }
        false
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let cargo_flags = env::var("CARGO_BUILD_TYPE").unwrap_or_else(|_| "debug".to_string());
    println!("Initializing core game module with build type: {}", cargo_flags);

    let mut state = GameState::new();
    state.process_move("WhiteKingToE4");
    state.process_move("BlackPawnMove");

    Ok(())
}

