use std::env;
use std::fs::File;
use std::io::{self, Write};
use std::path::PathBuf;

fn main() -> io::Result<()> {
    let output_dir = env::var("OUT_DIR")
        .expect("Failed to find OUT_DIR environment variable");

    let mut output_file = PathBuf::from(output_dir);
    output_file.push("team_data.txt");

    let mut file = File::create(&output_file)?;
    writeln!(&mut file, "TEAM_ID:NAME")?;
    writeln!(&mut file, "101:Lakers")?;
    writeln!(&mut file, "205:Celtics")?;
    writeln!(&mut file, "312:Bulls")?;

    println!("Generated dummy team data to: {}", output_file.display());
    Ok(())
}
